INDEX_HTML = "<!doctype html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"utf-8\" />\n    <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\" />\n    <title>Pico Bit Injector</title>\n    <link rel=\"stylesheet\" href=\"/assets/portal.css\" />\n  </head>\n  <body>\n    <nav class=\"topbar\">\n      <div class=\"topbar__brand\">Pico Bit</div>\n      <div class=\"topbar__fill\"></div>\n      <label class=\"switch\" for=\"unsafe-toggle\">\n        <span class=\"switch__label\">Unsafe mode</span>\n        <input\n          type=\"checkbox\"\n          id=\"unsafe-toggle\"\n          class=\"switch__input\"\n          role=\"switch\"\n          aria-label=\"Toggle unsafe mode\"\n        />\n        <span class=\"switch__track\" aria-hidden=\"true\">\n          <span class=\"switch__thumb\"></span>\n        </span>\n      </label>\n    </nav>\n\n    <main class=\"layout\">\n      <div class=\"stats\">\n        <div class=\"stat\">\n          <div class=\"stat__label\">Access point</div>\n          <div class=\"stat__value\" data-bind=\"ap_ssid\">picoBit</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat__label\">AP password</div>\n          <div class=\"stat__value stat__value--mono\" data-bind=\"ap_password\">\n            Open network\n          </div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat__label\">Portal auth</div>\n          <div class=\"stat__value\" data-bind=\"auth_label\">–</div>\n        </div>\n        <div class=\"stat\">\n          <div class=\"stat__label\">Host HID</div>\n          <div class=\"stat__value\" data-bind=\"hid_state\">Waiting</div>\n        </div>\n      </div>\n\n      <div class=\"workspace\">\n        <div class=\"editor\">\n          <div class=\"editor__bar\">\n            <div class=\"editor__file\">payload.dd</div>\n            <span class=\"badge\" data-bind=\"payload_state\">Saved on device</span>\n          </div>\n\n          <div class=\"notice notice--hidden\" id=\"notice\"></div>\n\n          <textarea\n            id=\"payload\"\n            class=\"editor__input\"\n            spellcheck=\"false\"\n            autocapitalize=\"off\"\n            autocomplete=\"off\"\n            autocorrect=\"off\"\n            placeholder=\"REM Write your payload here\"\n          ></textarea>\n\n          <div class=\"editor__footer\">\n            <p class=\"editor__note\" data-bind=\"mode_description\">\n              Safe mode active — unsafe commands are blocked.\n            </p>\n            <div class=\"editor__actions\">\n              <button class=\"btn btn--ghost\" id=\"refresh\" type=\"button\">\n                Reload\n              </button>\n              <button class=\"btn btn--ghost\" id=\"save\" type=\"button\">\n                Save\n              </button>\n              <button class=\"btn btn--primary\" id=\"run\" type=\"button\">\n                Save &amp; run\n              </button>\n            </div>\n          </div>\n        </div>\n\n        <aside class=\"sidebar\">\n          <div class=\"panel\">\n            <p class=\"panel__title\">About</p>\n            <p class=\"panel__text\">\n              Edit and execute <code>payload.dd</code> directly from the\n              browser. The portal stays live between runs — no reflashing\n              needed.\n            </p>\n            <ul class=\"panel__list\">\n              <li>File seeded on first boot if absent</li>\n              <li>Validation runs before every execution</li>\n              <li>HID access serialized — one script at a time</li>\n            </ul>\n          </div>\n\n          <div class=\"panel\">\n            <p class=\"panel__title\">Status</p>\n            <dl class=\"meta\">\n              <div class=\"meta__row\">\n                <span class=\"meta__label\">Payload file</span>\n                <span class=\"meta__value\">payload.dd</span>\n              </div>\n              <div class=\"meta__row\">\n                <span class=\"meta__label\">Seeded this boot</span>\n                <span class=\"meta__value\" data-bind=\"seeded\">No</span>\n              </div>\n              <div class=\"meta__row\">\n                <span class=\"meta__label\">Runtime mode</span>\n                <span class=\"meta__value\" data-bind=\"mode_label\">–</span>\n              </div>\n            </dl>\n            <div class=\"divider\"></div>\n            <form action=\"/logout\" method=\"post\">\n              <button class=\"btn btn--danger btn--wide\" type=\"submit\">\n                Sign out\n              </button>\n            </form>\n          </div>\n        </aside>\n      </div>\n    </main>\n\n    <script src=\"/assets/portal.js\"></script>\n  </body>\n</html>\n"

PORTAL_CSS = ":root {\n  color-scheme: light;\n\n  /* Surfaces — white on white hierarchy */\n  --bg: #ffffff;\n  --surface: #ffffff;\n  --surface-2: #fafafa;\n  --surface-3: #f5f5f7;\n\n  /* Borders */\n  --border: #e5e5e7;\n  --border-strong: #d2d2d7;\n\n  /* Text — monochrome */\n  --text: #000000;\n  --text-2: #1d1d1f;\n  --text-3: #6e6e73;\n  --text-4: #86868b;\n\n  /* Status accents only */\n  --success: #248a3d;\n  --success-bg: #ecf5ee;\n  --success-border: #c8e3cf;\n  --danger: #c4302b;\n  --danger-bg: #fdedeb;\n  --danger-border: #f5c8c4;\n\n  /* Type */\n  --sans: -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;\n  --mono: 'SF Mono', ui-monospace, 'Cascadia Mono', 'Menlo', monospace;\n}\n\n*,\n*::before,\n*::after {\n  box-sizing: border-box;\n}\n\nhtml {\n  font-size: 16px;\n}\n\nbody {\n  margin: 0;\n  min-height: 100vh;\n  font-family: var(--sans);\n  font-size: 14px;\n  line-height: 1.5;\n  color: var(--text-2);\n  background: var(--bg);\n  -webkit-font-smoothing: antialiased;\n  -moz-osx-font-smoothing: grayscale;\n}\n\ncode {\n  font-family: var(--mono);\n  font-size: 0.92em;\n  color: var(--text);\n}\n\na {\n  color: var(--text);\n}\n\n/* ─── Topbar ─────────────────────────────────── */\n.topbar {\n  display: flex;\n  align-items: center;\n  gap: 0.75rem;\n  height: 3rem;\n  padding: 0 1.5rem;\n  border-bottom: 1px solid var(--border);\n  background: var(--surface);\n}\n\n.topbar__brand {\n  font-size: 13px;\n  font-weight: 600;\n  letter-spacing: -0.01em;\n  color: var(--text);\n  user-select: none;\n}\n\n.topbar__fill {\n  flex: 1;\n}\n\n/* ─── Layout ─────────────────────────────────── */\n.layout {\n  max-width: 1100px;\n  margin: 0 auto;\n  padding: 1.5rem 1.5rem 4rem;\n  display: grid;\n  gap: 1rem;\n}\n\n/* ─── Stats ──────────────────────────────────── */\n.stats {\n  display: grid;\n  grid-template-columns: repeat(4, 1fr);\n  gap: 0.5rem;\n}\n\n.stat {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 10px;\n  padding: 0.75rem 0.875rem;\n}\n\n.stat__label {\n  font-size: 11px;\n  font-weight: 500;\n  color: var(--text-3);\n  margin-bottom: 0.3rem;\n}\n\n.stat__value {\n  font-size: 13px;\n  font-weight: 500;\n  color: var(--text);\n  line-height: 1.3;\n  word-break: break-all;\n}\n\n.stat__value--mono {\n  font-family: var(--mono);\n  font-size: 12px;\n}\n\n/* ─── Workspace ──────────────────────────────── */\n.workspace {\n  display: grid;\n  gap: 1rem;\n  align-items: start;\n}\n\n/* ─── Editor ─────────────────────────────────── */\n.editor {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 12px;\n  overflow: hidden;\n  display: flex;\n  flex-direction: column;\n}\n\n.editor__bar {\n  display: flex;\n  align-items: center;\n  gap: 0.625rem;\n  padding: 0.625rem 0.875rem;\n  border-bottom: 1px solid var(--border);\n  background: var(--surface-3);\n}\n\n.editor__file {\n  font-family: var(--mono);\n  font-size: 12px;\n  color: var(--text-3);\n  flex: 1;\n}\n\n.editor__input {\n  display: block;\n  width: 100%;\n  min-height: 28rem;\n  resize: vertical;\n  border: none;\n  background: var(--surface);\n  color: var(--text);\n  font-family: var(--mono);\n  font-size: 13px;\n  line-height: 1.7;\n  padding: 1rem;\n  outline: none;\n}\n\n.editor__footer {\n  display: flex;\n  align-items: center;\n  justify-content: space-between;\n  gap: 0.75rem;\n  padding: 0.75rem 0.875rem;\n  border-top: 1px solid var(--border);\n  background: var(--surface-3);\n  flex-wrap: wrap;\n}\n\n.editor__note {\n  font-size: 12px;\n  color: var(--text-3);\n  margin: 0;\n  flex: 1;\n  min-width: 0;\n  line-height: 1.5;\n}\n\n.editor__actions {\n  display: flex;\n  gap: 0.4rem;\n}\n\n/* ─── Notice banner ──────────────────────────── */\n.notice {\n  margin: 0.75rem 0.875rem 0;\n  border-radius: 8px;\n  padding: 0.5rem 0.75rem;\n  font-size: 12px;\n  line-height: 1.55;\n  border: 1px solid transparent;\n}\n\n.notice--hidden {\n  display: none;\n}\n.notice--quiet {\n  background: var(--surface-2);\n  border-color: var(--border);\n  color: var(--text-3);\n}\n.notice--success {\n  background: var(--success-bg);\n  border-color: var(--success-border);\n  color: var(--success);\n}\n.notice--error {\n  background: var(--danger-bg);\n  border-color: var(--danger-border);\n  color: var(--danger);\n}\n\n/* ─── Sidebar ────────────────────────────────── */\n.sidebar {\n  display: flex;\n  flex-direction: column;\n  gap: 0.875rem;\n}\n\n.panel {\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 12px;\n  padding: 1rem 1.125rem;\n}\n\n.panel__title {\n  font-size: 13px;\n  font-weight: 600;\n  color: var(--text);\n  margin: 0 0 0.625rem;\n  letter-spacing: -0.005em;\n}\n\n.panel__text {\n  font-size: 12px;\n  color: var(--text-3);\n  line-height: 1.6;\n  margin: 0 0 0.625rem;\n}\n\n.panel__list {\n  margin: 0;\n  padding-left: 1rem;\n  font-size: 12px;\n  color: var(--text-3);\n  line-height: 1.75;\n}\n\n.panel__list li {\n  margin-bottom: 0.15rem;\n}\n\n/* ─── Meta table ─────────────────────────────── */\n.meta {\n  display: grid;\n  margin: 0;\n}\n\n.meta__row {\n  display: flex;\n  justify-content: space-between;\n  align-items: center;\n  padding: 0.55rem 0;\n  border-top: 1px solid var(--border);\n  gap: 0.5rem;\n}\n\n.meta__row:first-child {\n  border-top: none;\n  padding-top: 0;\n}\n.meta__row:last-child {\n  padding-bottom: 0;\n}\n\n.meta__label {\n  font-size: 12px;\n  color: var(--text-3);\n}\n\n.meta__value {\n  font-size: 12px;\n  font-weight: 500;\n  color: var(--text);\n  text-align: right;\n}\n\n/* ─── Badge ──────────────────────────────────── */\n.badge {\n  display: inline-flex;\n  align-items: center;\n  border-radius: 6px;\n  padding: 0.18rem 0.5rem;\n  font-size: 11px;\n  font-weight: 500;\n  border: 1px solid var(--border);\n  background: var(--surface);\n  color: var(--text-3);\n  white-space: nowrap;\n}\n\n.badge--accent {\n  background: var(--text);\n  color: #ffffff;\n  border-color: var(--text);\n}\n\n/* ─── Toggle switch ──────────────────────────── */\n.switch {\n  display: inline-flex;\n  align-items: center;\n  gap: 0.55rem;\n  cursor: pointer;\n  user-select: none;\n}\n\n.switch__label {\n  font-size: 12px;\n  font-weight: 500;\n  color: var(--text-2);\n  letter-spacing: -0.005em;\n}\n\n.switch__input {\n  position: absolute;\n  opacity: 0;\n  width: 0;\n  height: 0;\n  pointer-events: none;\n}\n\n.switch__track {\n  position: relative;\n  display: inline-block;\n  width: 34px;\n  height: 20px;\n  border-radius: 999px;\n  background: var(--surface-3);\n  border: 1px solid var(--border-strong);\n  transition: background-color 0.15s ease, border-color 0.15s ease;\n  flex-shrink: 0;\n}\n\n.switch__thumb {\n  position: absolute;\n  top: 1px;\n  left: 1px;\n  width: 16px;\n  height: 16px;\n  border-radius: 50%;\n  background: #ffffff;\n  box-shadow: 0 1px 2px rgba(0, 0, 0, 0.18);\n  transition: transform 0.15s ease;\n}\n\n.switch__input:checked + .switch__track {\n  background: var(--danger);\n  border-color: var(--danger);\n}\n\n.switch__input:checked + .switch__track .switch__thumb {\n  transform: translateX(14px);\n}\n\n.switch__input:focus-visible + .switch__track {\n  box-shadow: 0 0 0 3px rgba(196, 48, 43, 0.18);\n}\n\n.switch__input:disabled + .switch__track {\n  opacity: 0.5;\n  cursor: not-allowed;\n}\n\n/* ─── Divider ────────────────────────────────── */\n.divider {\n  height: 1px;\n  background: var(--border);\n  margin: 0.875rem 0;\n}\n\n/* ─── Buttons ────────────────────────────────── */\n.btn {\n  display: inline-flex;\n  align-items: center;\n  justify-content: center;\n  appearance: none;\n  border: 1px solid transparent;\n  cursor: pointer;\n  font-family: inherit;\n  font-size: 13px;\n  font-weight: 500;\n  border-radius: 8px;\n  padding: 0.55rem 0.95rem;\n  white-space: nowrap;\n  text-decoration: none;\n  line-height: 1.2;\n}\n\n.btn:disabled {\n  opacity: 0.4;\n  cursor: not-allowed;\n}\n\n.btn--primary {\n  background: var(--text);\n  color: #ffffff;\n  border-color: var(--text);\n}\n\n.btn--primary:hover:not(:disabled) {\n  background: #2d2d2f;\n  border-color: #2d2d2f;\n}\n\n.btn--ghost {\n  background: var(--surface);\n  color: var(--text);\n  border-color: var(--border-strong);\n}\n\n.btn--ghost:hover:not(:disabled) {\n  background: var(--surface-2);\n}\n\n.btn--danger {\n  background: var(--surface);\n  color: var(--danger);\n  border-color: var(--border-strong);\n}\n\n.btn--danger:hover:not(:disabled) {\n  background: var(--danger-bg);\n  border-color: var(--danger-border);\n}\n\n.btn--wide {\n  width: 100%;\n}\n\n/* ─── Login page ─────────────────────────────── */\n.login-body {\n  min-height: 100vh;\n  display: grid;\n  place-items: center;\n  padding: 1.5rem;\n  background: var(--surface-3);\n}\n\n.login-card {\n  width: 100%;\n  max-width: 21rem;\n  padding: 1.875rem;\n  background: var(--surface);\n  border: 1px solid var(--border);\n  border-radius: 14px;\n}\n\n.login-header {\n  margin-bottom: 1.375rem;\n}\n\n.login-title {\n  font-size: 22px;\n  font-weight: 600;\n  color: var(--text);\n  letter-spacing: -0.025em;\n  margin: 0 0 0.375rem;\n}\n\n.login-hint {\n  font-size: 12px;\n  color: var(--text-3);\n  margin: 0;\n  line-height: 1.55;\n}\n\n.login-form {\n  display: grid;\n  gap: 0.75rem;\n}\n\n.field {\n  display: grid;\n  gap: 0.3rem;\n}\n\n.field__label {\n  font-size: 11px;\n  font-weight: 500;\n  color: var(--text-3);\n}\n\n.field__input {\n  appearance: none;\n  width: 100%;\n  border: 1px solid var(--border-strong);\n  border-radius: 8px;\n  background: var(--surface);\n  color: var(--text);\n  font-family: inherit;\n  font-size: 13px;\n  line-height: 1;\n  padding: 0.625rem 0.75rem;\n  outline: none;\n}\n\n.field__input:focus {\n  border-color: var(--text);\n}\n\n.login-form .notice {\n  margin: 0;\n}\n\n/* ─── Responsive ─────────────────────────────── */\n@media (min-width: 900px) {\n  .workspace {\n    grid-template-columns: minmax(0, 1fr) 17rem;\n  }\n}\n\n@media (max-width: 680px) {\n  .stats {\n    grid-template-columns: 1fr 1fr;\n  }\n\n  .layout {\n    padding: 1rem 1rem 3rem;\n  }\n\n  .editor__footer {\n    flex-direction: column;\n    align-items: stretch;\n  }\n\n  .editor__actions {\n    width: 100%;\n  }\n\n  .editor__actions .btn {\n    flex: 1;\n  }\n\n  .topbar {\n    padding: 0 1rem;\n  }\n}\n"

PORTAL_JS = "const notice = document.getElementById('notice');\nconst payloadField = document.getElementById('payload');\nconst saveButton = document.getElementById('save');\nconst runButton = document.getElementById('run');\nconst refreshButton = document.getElementById('refresh');\nconst unsafeToggle = document.getElementById('unsafe-toggle');\n\nfunction setNotice(message, tone = 'quiet') {\n  if (!notice) {\n    return;\n  }\n  if (!message) {\n    notice.className = 'notice notice--hidden';\n    notice.textContent = '';\n    return;\n  }\n  notice.className = `notice notice--${tone}`;\n  notice.textContent = message;\n}\n\nfunction setBoundText(name, value) {\n  document.querySelectorAll(`[data-bind=\"${name}\"]`).forEach((node) => {\n    node.textContent = value;\n  });\n}\n\nfunction setBusy(button, busy) {\n  if (!button) {\n    return;\n  }\n  button.disabled = busy;\n}\n\nasync function requestJson(path, options = {}) {\n  const response = await fetch(path, {\n    credentials: 'same-origin',\n    headers: {\n      'Content-Type': 'application/json',\n      ...options.headers,\n    },\n    ...options,\n  });\n\n  if (response.status === 401) {\n    window.location.href = '/login';\n    throw new Error('Unauthorized');\n  }\n\n  const data = await response.json().catch(() => ({}));\n  if (!response.ok) {\n    throw new Error(data.message || `Request failed with ${response.status}`);\n  }\n  return data;\n}\n\nfunction applyMode(state) {\n  setBoundText('mode_label', (state.mode_label || '').split(' ')[0]);\n  setBoundText('mode_short', state.mode_short);\n  setBoundText('mode_description', state.mode_description);\n  if (unsafeToggle) {\n    unsafeToggle.checked = !!state.allow_unsafe;\n  }\n}\n\nasync function loadBootstrap() {\n  const state = await requestJson('/api/bootstrap');\n  payloadField.value = state.payload || '';\n  setBoundText('ap_ssid', state.ap_ssid);\n  setBoundText('ap_password', state.ap_password || 'Open network');\n  applyMode(state);\n  setBoundText('seeded', state.seeded ? 'Yes' : 'No');\n  setBoundText('hid_state', state.keyboard_ready ? 'Ready' : 'Waiting');\n  setBoundText('auth_label', state.auth_enabled ? 'Enabled' : 'Disabled');\n  setBoundText(\n    'payload_state',\n    state.seeded ? 'Seeded on boot' : 'Saved on device',\n  );\n  setNotice(state.message || '', state.notice || 'quiet');\n}\n\nasync function toggleUnsafe(unsafeOn) {\n  setBusy(unsafeToggle, true);\n  try {\n    const result = await requestJson('/api/safe-mode', {\n      method: 'POST',\n      body: JSON.stringify({ enabled: !unsafeOn }),\n    });\n    applyMode(result);\n    setNotice(result.message, result.notice || 'success');\n  } catch (error) {\n    if (unsafeToggle) {\n      unsafeToggle.checked = !unsafeOn;\n    }\n    setNotice(error.message, 'error');\n  } finally {\n    setBusy(unsafeToggle, false);\n  }\n}\n\nasync function savePayload() {\n  setBusy(saveButton, true);\n  try {\n    const result = await requestJson('/api/payload', {\n      method: 'POST',\n      body: JSON.stringify({ payload: payloadField.value }),\n    });\n    setBoundText('payload_state', 'Saved on device');\n    setNotice(result.message, result.notice || 'success');\n  } catch (error) {\n    setNotice(error.message, 'error');\n  } finally {\n    setBusy(saveButton, false);\n  }\n}\n\nasync function runPayload() {\n  setBusy(runButton, true);\n  try {\n    const result = await requestJson('/api/run', {\n      method: 'POST',\n      body: JSON.stringify({ payload: payloadField.value, save: true }),\n    });\n    setBoundText('hid_state', 'Ready');\n    setNotice(result.message, result.notice || 'success');\n  } catch (error) {\n    setNotice(error.message, 'error');\n  } finally {\n    setBusy(runButton, false);\n  }\n}\n\nif (refreshButton) {\n  refreshButton.addEventListener('click', () => {\n    loadBootstrap().catch((error) => setNotice(error.message, 'error'));\n  });\n}\n\nif (saveButton) {\n  saveButton.addEventListener('click', () => {\n    savePayload();\n  });\n}\n\nif (runButton) {\n  runButton.addEventListener('click', () => {\n    runPayload();\n  });\n}\n\nif (unsafeToggle) {\n  unsafeToggle.addEventListener('change', () => {\n    toggleUnsafe(unsafeToggle.checked);\n  });\n}\n\nloadBootstrap().catch((error) => setNotice(error.message, 'error'));\n"

